#!/usr/bin/env node
/**
 * @script            fetch-exchanges-data
 * @category          automation
 * @purpose           infrastructure:data-feeds
 * @scope             .github/scripts
 * @owner             docs
 * @needs             F-R1
 * @purpose-statement Fetches LPT exchange tickers from CoinGecko API, classifies CEX/DEX, writes structured JSX data for SearchTable consumption.
 * @pipeline          P5 (scheduled, weekly)
 * @dualmode          --dry-run (fetch + preview, no write) | default (fetch + write)
 * @usage             node .github/scripts/fetch-exchanges-data.js [--dry-run]
 */

const https = require('https');
const fs = require('fs');
const path = require('path');

const COIN_ID = process.env.COINGECKO_COIN_ID || 'livepeer';
const API_BASE = 'https://api.coingecko.com/api/v3';
const OUTPUT_PATH = path.resolve(__dirname, '../../snippets/data/exchanges/exchangesData.jsx');

const DRY_RUN = process.argv.includes('--dry-run');

function httpsGet(url) {
  return new Promise((resolve, reject) => {
    https
      .get(url, { headers: { 'User-Agent': 'livepeer-docs-bot/1.0' } }, (res) => {
        let data = '';
        res.on('data', (chunk) => (data += chunk));
        res.on('end', () => {
          try {
            resolve(JSON.parse(data));
          } catch (e) {
            reject(new Error(`Failed to parse response from ${url}: ${e.message}`));
          }
        });
      })
      .on('error', reject);
  });
}

function escapeForJSX(str) {
  if (!str) return '';
  return str
    .replace(/\\/g, '\\\\')
    .replace(/'/g, "\\'")
    .replace(/"/g, '\\"')
    .replace(/\n/g, ' ')
    .replace(/\r/g, '')
    .replace(/\t/g, ' ');
}

function trustScoreEmoji(score) {
  if (score === 'green') return '🟢';
  if (score === 'yellow') return '🟡';
  if (score === 'red') return '🔴';
  return '⚪';
}

function classifyExchange(ticker) {
  // CoinGecko marks decentralised exchanges
  if (ticker.market && ticker.market.identifier) {
    const id = ticker.market.identifier.toLowerCase();
    const dexIndicators = ['uniswap', 'sushiswap', 'curve', 'balancer', 'pancake', 'quickswap', 'camelot', 'aerodrome', 'velodrome', 'trader_joe'];
    if (dexIndicators.some(d => id.includes(d))) return 'DEX';
  }
  return 'CEX';
}

async function fetchAllTickers() {
  let allTickers = [];
  let page = 1;
  const maxPages = 5;

  while (page <= maxPages) {
    console.log(`Fetching tickers page ${page}...`);
    const url = `${API_BASE}/coins/${COIN_ID}/tickers?page=${page}&depth=true`;
    const data = await httpsGet(url);

    if (!data.tickers || data.tickers.length === 0) break;
    allTickers = allTickers.concat(data.tickers);
    page++;

    // Rate limit: CoinGecko free tier allows ~10-30 req/min
    if (page <= maxPages) await new Promise(r => setTimeout(r, 2000));
  }

  return allTickers;
}

function deduplicateExchanges(tickers) {
  const seen = new Map();

  for (const ticker of tickers) {
    const exchangeName = ticker.market?.name || 'Unknown';
    const key = exchangeName.toLowerCase();

    if (!seen.has(key)) {
      seen.set(key, {
        Exchange: escapeForJSX(exchangeName),
        Type: classifyExchange(ticker),
        TrustScore: trustScoreEmoji(ticker.trust_score),
        'Trading Pair': `${ticker.base}/${ticker.target}`,
        URL: ticker.trade_url || '',
        Volume24h: ticker.converted_volume?.usd ? `$${Math.round(ticker.converted_volume.usd).toLocaleString()}` : 'N/A',
      });
    } else {
      // If same exchange has multiple pairs, keep the highest volume one
      const existing = seen.get(key);
      const existingVol = parseFloat(existing.Volume24h.replace(/[$,]/g, '')) || 0;
      const newVol = ticker.converted_volume?.usd || 0;
      if (newVol > existingVol) {
        seen.set(key, {
          Exchange: escapeForJSX(exchangeName),
          Type: classifyExchange(ticker),
          TrustScore: trustScoreEmoji(ticker.trust_score),
          'Trading Pair': `${ticker.base}/${ticker.target}`,
          URL: ticker.trade_url || '',
          Volume24h: `$${Math.round(newVol).toLocaleString()}`,
        });
      }
    }
  }

  return Array.from(seen.values()).sort((a, b) => a.Exchange.localeCompare(b.Exchange));
}

function generateJSX(exchanges) {
  const timestamp = new Date().toISOString();

  return `/**
 * DO NOT EDIT MANUALLY — auto-generated by fetch-exchanges-data.js
 * Last updated: ${timestamp}
 * Source: CoinGecko API (coins/${COIN_ID}/tickers)
 * Workflow: .github/workflows/update-exchanges-data.yml
 *
 * @typedef {Object} Exchange
 * @property {string} Exchange - Exchange name
 * @property {string} Type - CEX or DEX
 * @property {string} TrustScore - Trust score emoji
 * @property {string} 'Trading Pair' - Primary trading pair
 * @property {string} URL - Trade URL
 * @property {string} Volume24h - 24h volume in USD
 */
export const exchangesData = [
${exchanges.map(ex => `  {
    Exchange: '${ex.Exchange}',
    Type: '${ex.Type}',
    TrustScore: '${ex.TrustScore}',
    'Trading Pair': '${ex['Trading Pair']}',
    URL: '${ex.URL}',
    Volume24h: '${ex.Volume24h}',
  }`).join(',\n')}
];

export const exchangesMetadata = {
  lastUpdated: '${timestamp}',
  source: 'CoinGecko API',
  coinId: '${COIN_ID}',
  totalExchanges: ${exchanges.length},
  cex: ${exchanges.filter(e => e.Type === 'CEX').length},
  dex: ${exchanges.filter(e => e.Type === 'DEX').length},
};
`;
}

async function main() {
  console.log(`Fetching exchange data for ${COIN_ID}...`);

  const tickers = await fetchAllTickers();
  console.log(`Fetched ${tickers.length} tickers`);

  const exchanges = deduplicateExchanges(tickers);
  console.log(`Deduplicated to ${exchanges.length} unique exchanges`);
  console.log(`  CEX: ${exchanges.filter(e => e.Type === 'CEX').length}`);
  console.log(`  DEX: ${exchanges.filter(e => e.Type === 'DEX').length}`);

  const jsxContent = generateJSX(exchanges);

  if (DRY_RUN) {
    console.log('\n--- DRY RUN (preview) ---');
    console.log(jsxContent.slice(0, 500) + '...');
    console.log(`\nWould write ${jsxContent.length} bytes to ${OUTPUT_PATH}`);
  } else {
    const dir = path.dirname(OUTPUT_PATH);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    fs.writeFileSync(OUTPUT_PATH, jsxContent);
    console.log(`Wrote ${exchanges.length} exchanges to ${OUTPUT_PATH}`);
  }
}

main().catch((err) => {
  console.error('Error:', err.message);
  process.exit(1);
});
